using UnityEngine;

/// <summary>
/// Pickup de Melodia Selvagem — ao ser recolhido, desbloqueia a melodia
/// correspondente no Jukebox e registra o progresso na área.
///
/// Herda de <see cref="PickupBase"/> (persistência / anti-duplicação via
/// pickupId) e usa o sistema de eventos de <see cref="PlayerProgress"/> para
/// notificar o resto do jogo.
///
/// Montagem no Editor:
/// - Adicionar à cena como prefab de collectible.
/// - "melody": WildMelodyData desta melodia.
/// - "pickupId" (herdado): ID único do pickup (ex: "melodia_floresta_01").
/// - "area" (herdado): AreaData da área.
/// - "popupText" (herdado): ex: "Melodia Selvagem: Canto Noturno".
/// - "autosaveOnCollect" (herdado): recomendado true (melodia é coleccionável único).
/// </summary>
public class WildMelodyPickup : PickupBase
{
    [Header("Melodia")]
    [Tooltip("WildMelodyData desta melodia selvagem.")]
    [SerializeField] private WildMelodyData melody;

    public override PickupType Type => PickupType.WildMelody;

    protected override void GrantReward()
    {
        if (melody == null) return;

        var progress = PlayerProgress.Instance;
        if (progress == null) return;

        // Registar a melodia como colectada em PlayerProgress.
        progress.MarkMelodyCollected(melody.melodyId, area ?? melody.area);

        // Notificar o Jukebox de que uma nova melodia está disponível.
        JukeboxSectionUI.NotifyMelodyCollected(melody);
    }
}
